node --input-type=module <<'EOF'
import { connect } from './packages/web-skills/skills/web-browser/scripts/cdp.js';

const c = await connect();
const pages = await c.getPages();
const page = [...pages].reverse().find((p) => p.url.includes('/package/typescript'));
if (!page) throw new Error('typescript tab not found');
const sessionId = await c.attachToPage(page.targetId);

const data = await c.evaluate(
  sessionId,
  `(() => {
    const txt = document.body.innerText;
    const firstNonEmptyAfter = (label) => {
      const i = txt.indexOf(label);
      if (i === -1) return null;
      const after = txt.slice(i + label.length).split(/\\n/).map((l) => l.trim()).filter(Boolean);
      return after[0] || null;
    };
    return {
      title: document.title,
      url: location.href,
      packageName: (document.querySelector('h2')?.textContent || '').trim() || null,
      weeklyDownloads: firstNonEmptyAfter('Weekly Downloads'),
      version: firstNonEmptyAfter('Version'),
      license: firstNonEmptyAfter('License')
    };
  })()`
);

console.log(JSON.stringify(data, null, 2));
c.close();
EOF

